#include<iostream>#include<algorithm>#include<vector>#define dl double#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<pair<ll,ll>> v(n);        for(int i=0;i<n;i++){            cin>>v[i].first>>v[i].second;        }        dl next=0.0;        for (int  i = n-1; i >= 0; i--){           dl c_i= v[i].first;           dl p_i= v[i].second;           dl mul= 1.0 - (p_i/100.0);           dl skip= next;           dl take= c_i + (mul*next);            next= max(skip,take);                }        cout<<fixed;        cout.precision(6);        cout<<next<<"\n";    }}